const PptxGenJS = require("pptxgenjs");

const pres = new PptxGenJS();
pres.layout = "LAYOUT_16x9";
pres.title = "Agentic DevOps: The Playbook for Working Engineers";
pres.author = "KodeKloud";

// ─── COLOR PALETTE ───────────────────────────────────────────────────────────
const C = {
  navy:     "1E2761",   // dominant background
  iceblue:  "CADCFC",   // supporting / accents
  white:    "FFFFFF",
  lightbg:  "F0F4FF",   // light slide backgrounds
  midblue:  "3A5BA0",   // secondary navy elements
  darkgray: "2A2A3A",   // body text on light slides
  muted:    "6B7A9E",   // captions / muted
  amber:    "F0A500",   // warning accents
  red:      "D94F3D",   // risk accents
  green:    "2EA86E",   // check/positive accents
  panelbg:  "E8EEFF",   // card backgrounds on light slides
};

// ─── TYPOGRAPHY ──────────────────────────────────────────────────────────────
const F = {
  head: "Trebuchet MS",
  body: "Calibri",
};

// ─── HELPERS ─────────────────────────────────────────────────────────────────
function darkSlide(s) { s.background = { color: C.navy }; }
function lightSlide(s) { s.background = { color: C.lightbg }; }

// Section badge (numbered circle) for dark slides
function addBadge(s, num, x, y, bg, fg) {
  s.addShape(pres.shapes.OVAL, { x, y, w: 0.65, h: 0.65, fill: { color: bg || C.iceblue }, line: { color: bg || C.iceblue } });
  s.addText(String(num), { x, y: y + 0.01, w: 0.65, h: 0.65, align: "center", valign: "middle", fontSize: 22, bold: true, fontFace: F.head, color: fg || C.navy, margin: 0 });
}

// Thin top bar accent (navy slides get iceblue bar, light slides get navy bar)
function addTopBar(s, dark) {
  s.addShape(pres.shapes.RECTANGLE, { x: 0, y: 0, w: 10, h: 0.07, fill: { color: dark ? C.iceblue : C.navy }, line: { color: dark ? C.iceblue : C.navy } });
}

// Card box helper
function card(s, x, y, w, h, bg, borderColor) {
  s.addShape(pres.shapes.RECTANGLE, {
    x, y, w, h,
    fill: { color: bg || C.panelbg },
    line: { color: borderColor || C.iceblue, width: 1.5 },
    shadow: { type: "outer", blur: 4, offset: 2, angle: 135, color: "000000", opacity: 0.10 }
  });
}

// KodeKloud brand tag bottom right
function addBrand(s, dark) {
  s.addText("KodeKloud", { x: 7.8, y: 5.25, w: 2.0, h: 0.25, fontSize: 9, fontFace: F.body, color: dark ? C.iceblue : C.muted, align: "right", italic: true });
}

// ─── SLIDE 0: TITLE HOLD SCREEN ───────────────────────────────────────────────
{
  const s = pres.addSlide();
  darkSlide(s);

  // Background decorative circles
  s.addShape(pres.shapes.OVAL, { x: -0.5, y: -0.5, w: 3, h: 3, fill: { color: "243180", transparency: 70 }, line: { color: "243180", transparency: 70 } });
  s.addShape(pres.shapes.OVAL, { x: 8, y: 3.5, w: 2.5, h: 2.5, fill: { color: "243180", transparency: 70 }, line: { color: "243180", transparency: 70 } });

  s.addText("AGENTIC DEVOPS", { x: 1, y: 1.5, w: 8, h: 0.9, align: "center", fontSize: 44, bold: true, fontFace: F.head, color: C.white, charSpacing: 4 });
  s.addText("The Playbook for Working Engineers", { x: 1, y: 2.5, w: 8, h: 0.5, align: "center", fontSize: 20, fontFace: F.body, color: C.iceblue });

  s.addShape(pres.shapes.LINE, { x: 2.5, y: 3.15, w: 5, h: 0, line: { color: C.iceblue, width: 1 } });

  s.addText("Live Session  |  April 2026  |  KodeKloud", { x: 1, y: 3.3, w: 8, h: 0.35, align: "center", fontSize: 13, fontFace: F.body, color: C.iceblue, italic: true });

  s.addNotes("PRE-SESSION — Title Hold Screen\n\nHave your outline open in a second window. Know your five section transitions cold.\n\nWater nearby. Chat window open. Check: mic levels, camera framing, slide advancer working, backup slides loaded.\n\nPlay holding music or ambient screen while people join.");
}

// ─── SLIDE 1: TITLE SLIDE ──────────────────────────────────────────────────
{
  const s = pres.addSlide();
  darkSlide(s);
  addTopBar(s, true);

  s.addShape(pres.shapes.OVAL, { x: 7.5, y: -1, w: 4, h: 4, fill: { color: "253280", transparency: 60 }, line: { color: "253280", transparency: 60 } });
  s.addShape(pres.shapes.OVAL, { x: -1, y: 3.5, w: 3, h: 3, fill: { color: "253280", transparency: 60 }, line: { color: "253280", transparency: 60 } });

  s.addText("AGENTIC DEVOPS", { x: 0.6, y: 0.9, w: 8.5, h: 1.0, align: "left", fontSize: 48, bold: true, fontFace: F.head, color: C.white, charSpacing: 3 });
  s.addText("The Playbook for Working Engineers", { x: 0.6, y: 1.95, w: 8, h: 0.55, align: "left", fontSize: 22, fontFace: F.body, color: C.iceblue });

  s.addShape(pres.shapes.LINE, { x: 0.6, y: 2.65, w: 5, h: 0, line: { color: C.iceblue, width: 1.5 } });

  s.addText("[Your Name]", { x: 0.6, y: 2.85, w: 6, h: 0.4, fontSize: 16, bold: true, fontFace: F.head, color: C.white });
  s.addText("Senior Principal Trainer & DevOps Advocate", { x: 0.6, y: 3.22, w: 7, h: 0.3, fontSize: 13, fontFace: F.body, color: C.iceblue });
  s.addText("KodeKloud  |  April 2026", { x: 0.6, y: 3.55, w: 5, h: 0.28, fontSize: 12, fontFace: F.body, color: C.muted, italic: true });

  addBrand(s, true);

  s.addNotes("[TIMING: 0:00]\n\n\"Before we get into frameworks and tools, I want to start with something that happened two months ago that stopped me mid-scroll.\"\n\n\"Anthropic's Claude Code is now writing 100% of Anthropic's own code. Not assisting. Writing.\"\n\n[PAUSE — let that register]\n\n\"And in the same week, Boris Cherny — the Head of Claude Code — replied to the obvious follow-up: 'So why does Anthropic still have 100 open engineering positions?'\"\n\n\"His answer: someone has to prompt the models, talk to customers, coordinate teams, and decide what to build next.\"\n\n[PAUSE]\n\n\"That's not a reassurance. That's a job description. And it looks a lot like what strong DevOps engineers already do.\"\n\n\"That's what the next 50 minutes is about. The real question is: what does your job look like on the other side of this shift?\"");
}

// ─── SLIDE 2: THE WEEK EVERYTHING CHANGED ─────────────────────────────────
{
  const s = pres.addSlide();
  darkSlide(s);
  addTopBar(s, true);

  s.addText("ONE WEEK. DECEMBER 2025.", { x: 0.5, y: 0.3, w: 9, h: 0.55, align: "center", fontSize: 28, bold: true, fontFace: F.head, color: C.white, charSpacing: 2 });
  s.addText("All three major cloud platforms shipped autonomous DevOps agents in the same week.", { x: 0.8, y: 0.95, w: 8.4, h: 0.35, align: "center", fontSize: 13, fontFace: F.body, color: C.iceblue, italic: true });

  const cols = [
    { title: "AWS", sub: "DevOps Agent", tag: "Public Preview", color: "FF9900" },
    { title: "MICROSOFT", sub: "SRE Agent", tag: "Preview", color: "00BCF2" },
    { title: "GOOGLE", sub: "ADK Expansion", tag: "+4 Major Tools", color: "34A853" },
  ];

  cols.forEach((c, i) => {
    const x = 0.55 + i * 3.05;
    s.addShape(pres.shapes.RECTANGLE, { x, y: 1.5, w: 2.85, h: 2.8, fill: { color: "253280" }, line: { color: C.iceblue, width: 1.5 } });
    s.addShape(pres.shapes.RECTANGLE, { x, y: 1.5, w: 2.85, h: 0.5, fill: { color: c.color }, line: { color: c.color } });
    s.addText(c.title, { x, y: 1.5, w: 2.85, h: 0.5, align: "center", valign: "middle", fontSize: 14, bold: true, fontFace: F.head, color: C.white, margin: 0 });
    s.addText(c.sub, { x, y: 2.15, w: 2.85, h: 0.5, align: "center", fontSize: 18, bold: true, fontFace: F.head, color: C.white });
    s.addText(c.tag, { x, y: 2.75, w: 2.85, h: 0.35, align: "center", fontSize: 13, fontFace: F.body, color: C.iceblue, italic: true });
    s.addShape(pres.shapes.LINE, { x: x + 0.3, y: 3.25, w: 2.25, h: 0, line: { color: C.iceblue, width: 0.75 } });
    s.addText("Autonomous operations", { x, y: 3.35, w: 2.85, h: 0.3, align: "center", fontSize: 11, fontFace: F.body, color: C.muted });
    s.addText("of DevOps workflows", { x, y: 3.65, w: 2.85, h: 0.3, align: "center", fontSize: 11, fontFace: F.body, color: C.muted });
  });

  s.addText("That's not a coincidence. That's a race. Agentic operations is the next platform layer every major cloud is competing on.", { x: 0.55, y: 4.5, w: 8.9, h: 0.45, align: "center", fontSize: 13, fontFace: F.body, color: C.iceblue, bold: true });

  addBrand(s, true);

  s.addNotes("[TIMING: 1:00]\n\n\"In the first week of December 2025, at AWS re:Invent, Microsoft Azure, and Google Cloud events — all three shipped autonomous DevOps agents. In the same week.\"\n\n\"Not AI assistants. Agents. Systems that can autonomously investigate incidents, analyze CI failures, propose infrastructure changes — and in some configurations, execute them.\"\n\n\"That's not a coincidence. That's a race. And every major cloud platform has decided that agentic operations is the next platform layer they're competing on.\"\n\n\"Which means your infrastructure — your Kubernetes clusters, your CI/CD pipelines, your observability stack — is about to become the runtime these agents operate on.\"\n\n[PAUSE]\n\n\"If you're a DevOps engineer who understands those systems, you are not obsolete. You are the foundation.\"");
}

// ─── SLIDE 3: THE HONEST NUMBERS ──────────────────────────────────────────
{
  const s = pres.addSlide();
  lightSlide(s);
  addTopBar(s, false);

  s.addText("WHAT'S ACTUALLY HAPPENING RIGHT NOW", { x: 0.5, y: 0.2, w: 9, h: 0.55, align: "center", fontSize: 22, bold: true, fontFace: F.head, color: C.navy, charSpacing: 1 });

  const stats = [
    { big: "1M+", label: "PRs created by\nGitHub Copilot\nautonomously\n(May–Sept 2025)", x: 0.4, y: 0.9 },
    { big: "46%", label: "of active Copilot\nusers' code is\nAI-generated", x: 3.55, y: 0.9 },
    { big: "4.6×", label: "longer AI-generated\nPRs wait for review\nvs. human PRs", x: 6.7, y: 0.9 },
    { big: "2,000", label: "Production envs\nwhere Datadog\nAI SRE Agent\nis running", x: 0.4, y: 3.0 },
    { big: "90%", label: "of Fortune 100\ncompanies now\nusing GitHub\nCopilot", x: 3.55, y: 3.0 },
  ];

  // Row 1 cards
  for (let i = 0; i < 3; i++) {
    const st = stats[i];
    card(s, st.x, st.y, 2.8, 1.85, C.panelbg, C.iceblue);
    s.addShape(pres.shapes.RECTANGLE, { x: st.x, y: st.y, w: 2.8, h: 0.06, fill: { color: C.navy }, line: { color: C.navy } });
    s.addText(st.big, { x: st.x, y: st.y + 0.15, w: 2.8, h: 0.75, align: "center", fontSize: 40, bold: true, fontFace: F.head, color: C.navy });
    s.addText(st.label, { x: st.x, y: st.y + 0.9, w: 2.8, h: 0.9, align: "center", fontSize: 11, fontFace: F.body, color: C.darkgray });
  }

  // Row 2 cards (2 wide)
  for (let i = 3; i < 5; i++) {
    const st = stats[i];
    card(s, st.x, st.y, 2.8, 1.85, C.panelbg, C.iceblue);
    s.addShape(pres.shapes.RECTANGLE, { x: st.x, y: st.y, w: 2.8, h: 0.06, fill: { color: C.navy }, line: { color: C.navy } });
    s.addText(st.big, { x: st.x, y: st.y + 0.15, w: 2.8, h: 0.75, align: "center", fontSize: 40, bold: true, fontFace: F.head, color: C.navy });
    s.addText(st.label, { x: st.x, y: st.y + 0.9, w: 2.8, h: 0.9, align: "center", fontSize: 11, fontFace: F.body, color: C.darkgray });
  }

  s.addText("Source: GitHub, Opsera 2026, Datadog", { x: 0.5, y: 5.25, w: 9, h: 0.2, align: "right", fontSize: 9, fontFace: F.body, color: C.muted, italic: true });

  addBrand(s, false);

  s.addNotes("[TIMING: 2:00]\n\n\"Let me give you the numbers that matter.\"\n\n\"GitHub Copilot's Coding Agent has created over one million pull requests autonomously since May 2025. That's an agent receiving an issue ticket and delivering a PR — without a human writing a single line.\"\n\n[CLICK] \"46% of active Copilot users' code is now AI-generated. Not suggested — generated.\"\n\n[CLICK] \"Here's the number that tells you the real story: those AI-generated PRs wait 4.6 times longer to be reviewed than human-written PRs.\"\n\n[PAUSE]\n\n\"Think about what that means. We solved the code-writing bottleneck with AI — and immediately created a new bottleneck in the outer loop. Review, testing, deployment, incident response.\"\n\n\"That outer loop — that's where DevOps engineers live. And that's exactly where agentic AI is moving next.\"");
}

// ─── SLIDE 4: WHAT THIS WEBINAR IS AND ISN'T ──────────────────────────────
{
  const s = pres.addSlide();
  lightSlide(s);
  addTopBar(s, false);

  s.addText("THIS WEBINAR", { x: 0.5, y: 0.2, w: 9, h: 0.5, align: "center", fontSize: 24, bold: true, fontFace: F.head, color: C.navy, charSpacing: 2 });

  // IS column
  card(s, 0.4, 0.9, 4.2, 4.2, C.panelbg, C.navy);
  s.addShape(pres.shapes.RECTANGLE, { x: 0.4, y: 0.9, w: 4.2, h: 0.45, fill: { color: C.navy }, line: { color: C.navy } });
  s.addText("WHAT THIS IS", { x: 0.4, y: 0.9, w: 4.2, h: 0.45, align: "center", valign: "middle", fontSize: 14, bold: true, fontFace: F.head, color: C.white, margin: 0 });

  const isItems = [
    { icon: "✓", text: "A decision framework for working engineers" },
    { icon: "✓", text: "Grounded in what's confirmed in production right now" },
    { icon: "✓", text: "A 90-day plan you can start Monday" },
  ];
  isItems.forEach((item, i) => {
    const y = 1.55 + i * 1.1;
    s.addShape(pres.shapes.OVAL, { x: 0.65, y: y, w: 0.4, h: 0.4, fill: { color: C.green }, line: { color: C.green } });
    s.addText(item.icon, { x: 0.65, y: y, w: 0.4, h: 0.4, align: "center", valign: "middle", fontSize: 13, color: C.white, margin: 0 });
    s.addText(item.text, { x: 1.15, y: y, w: 3.25, h: 0.4, fontSize: 13, fontFace: F.body, color: C.darkgray, valign: "middle" });
  });

  // ISN'T column
  card(s, 5.4, 0.9, 4.2, 4.2, C.panelbg, C.red);
  s.addShape(pres.shapes.RECTANGLE, { x: 5.4, y: 0.9, w: 4.2, h: 0.45, fill: { color: C.red }, line: { color: C.red } });
  s.addText("WHAT THIS ISN'T", { x: 5.4, y: 0.9, w: 4.2, h: 0.45, align: "center", valign: "middle", fontSize: 14, bold: true, fontFace: F.head, color: C.white, margin: 0 });

  const isntItems = [
    { icon: "✕", text: "A tools demo" },
    { icon: "✕", text: "Hype about what's possible in 2030" },
    { icon: "✕", text: "A message that your skills are becoming worthless" },
  ];
  isntItems.forEach((item, i) => {
    const y = 1.55 + i * 1.1;
    s.addShape(pres.shapes.OVAL, { x: 5.65, y: y, w: 0.4, h: 0.4, fill: { color: C.red }, line: { color: C.red } });
    s.addText(item.icon, { x: 5.65, y: y, w: 0.4, h: 0.4, align: "center", valign: "middle", fontSize: 13, color: C.white, margin: 0 });
    s.addText(item.text, { x: 6.15, y: y, w: 3.25, h: 0.4, fontSize: 13, fontFace: F.body, color: C.darkgray, valign: "middle" });
  });

  addBrand(s, false);

  s.addNotes("[TIMING: 3:30]\n\n\"Before we go further, let me tell you exactly what you're going to get and what you're not.\"\n\n\"This is a decision framework. By the end you'll know what agentic DevOps actually is, where the real use cases are, what skills you need to build, and a 90-day plan that starts with one concrete action.\"\n\n\"This is not a vendor demo. I'm going to show you what's confirmed in production at companies like Elastic, Datadog, and Block — not what a vendor says is possible.\"\n\n[PAUSE]\n\n\"And this is absolutely not a message that your Kubernetes skills, your CI/CD expertise, your observability knowledge are becoming worthless. They're the foundation agents run on.\"\n\n\"Let's get into it.\"");
}

// ─── SLIDE 5: SECTION HEADER 2 ────────────────────────────────────────────
{
  const s = pres.addSlide();
  darkSlide(s);

  s.addShape(pres.shapes.OVAL, { x: 8, y: -0.5, w: 4, h: 4, fill: { color: "243180", transparency: 70 }, line: { color: "243180", transparency: 70 } });

  addBadge(s, "2", 4.65, 1.1);

  s.addText("WHAT IS AGENTIC DEVOPS,", { x: 1, y: 1.9, w: 8, h: 0.65, align: "center", fontSize: 30, bold: true, fontFace: F.head, color: C.white, charSpacing: 1 });
  s.addText("ACTUALLY", { x: 1, y: 2.55, w: 8, h: 0.65, align: "center", fontSize: 30, bold: true, fontFace: F.head, color: C.iceblue, charSpacing: 1 });
  s.addText("Cutting through the noise with a definition that sticks", { x: 1.5, y: 3.35, w: 7, h: 0.4, align: "center", fontSize: 15, fontFace: F.body, color: C.muted, italic: true });

  addBrand(s, true);

  s.addNotes("[TIMING: 5:00]\n\n\"The phrase 'agentic AI' is everywhere right now. Before we can talk about what to do about it, we need a definition that's actually useful — not marketing language.\"");
}

// ─── SLIDE 6: THE THREE WAVES ─────────────────────────────────────────────
{
  const s = pres.addSlide();
  lightSlide(s);
  addTopBar(s, false);

  s.addText("THREE WAVES OF AI IN DEVOPS", { x: 0.5, y: 0.2, w: 9, h: 0.5, align: "center", fontSize: 22, bold: true, fontFace: F.head, color: C.navy, charSpacing: 1 });

  const waves = [
    { num: "1", title: "Pair Programmer", years: "2021 – 2023", desc: "Code completion in your IDE. You're present for every keystroke.", status: "WHERE ARE\nYOU NOW?", statusBg: C.muted, bg: C.panelbg, border: C.iceblue },
    { num: "2", title: "AI-Assisted", years: "2023 – 2025", desc: "Chat help, code review, vulnerability scanning. Reactive — you ask, it answers.", status: "WHERE MOST\nTEAMS ARE TODAY", statusBg: C.midblue, bg: C.panelbg, border: C.midblue },
    { num: "3", title: "Agentic", years: "2025 – Present", desc: "Autonomous agents operating for hours without oversight. Plans, executes, iterates.", status: "WHERE\nTHIS IS GOING", statusBg: C.navy, bg: "E0E8FF", border: C.navy },
  ];

  waves.forEach((w, i) => {
    const x = 0.4 + i * 3.1;
    card(s, x, 0.85, 2.95, 4.35, w.bg, w.border);
    s.addShape(pres.shapes.RECTANGLE, { x, y: 0.85, w: 2.95, h: 0.45, fill: { color: w.statusBg }, line: { color: w.statusBg } });
    addBadge(s, w.num, x + 1.15, 0.85, w.statusBg === C.navy ? C.iceblue : C.white, C.navy);
    s.addText(w.title, { x: x + 0.1, y: 1.45, w: 2.75, h: 0.5, align: "center", fontSize: 18, bold: true, fontFace: F.head, color: C.navy });
    s.addText(w.years, { x: x + 0.1, y: 1.95, w: 2.75, h: 0.3, align: "center", fontSize: 11, fontFace: F.body, color: C.muted, italic: true });
    s.addShape(pres.shapes.LINE, { x: x + 0.3, y: 2.3, w: 2.35, h: 0, line: { color: C.iceblue, width: 0.75 } });
    s.addText(w.desc, { x: x + 0.15, y: 2.4, w: 2.65, h: 1.2, fontSize: 12, fontFace: F.body, color: C.darkgray, align: "center" });
    card(s, x + 0.15, 3.75, 2.65, 0.65, w.statusBg, w.statusBg);
    s.addText(w.status, { x: x + 0.15, y: 3.75, w: 2.65, h: 0.65, align: "center", valign: "middle", fontSize: 11, bold: true, fontFace: F.head, color: C.white });
  });

  s.addText("Wave 3: Agents receive a goal and operate independently for hours — planning, executing, and handing off to other agents.", { x: 0.5, y: 5.25, w: 9, h: 0.25, align: "center", fontSize: 10, fontFace: F.body, color: C.muted, italic: true });

  addBrand(s, false);

  s.addNotes("[TIMING: 5:30]\n\nWave 1: GitHub Copilot original. Code completion. You're in the IDE, every action has a human in the loop.\n\n[CLICK] Wave 2: where most teams are today. Chat-based assistance, code review, vulnerability scanning. Still reactive.\n\n[CLICK] Wave 3 is what we're talking about. Autonomous agents that receive a goal — 'fix this broken CI build,' 'investigate this incident' — and operate independently for hours.\n\n[PAUSE] The reason this distinction matters: most of the panic about AI taking DevOps jobs is people applying Wave 3 fears to Wave 2 reality. Wave 2 doesn't restructure your job. Wave 3 does. And Wave 3 is here — but it's early, and you have time to get positioned.");
}

// ─── SLIDE 7: INNER LOOP vs OUTER LOOP ────────────────────────────────────
{
  const s = pres.addSlide();
  lightSlide(s);
  addTopBar(s, false);

  s.addText("WHERE THE BOTTLENECK MOVED", { x: 0.5, y: 0.2, w: 9, h: 0.5, align: "center", fontSize: 22, bold: true, fontFace: F.head, color: C.navy, charSpacing: 1 });

  // Inner loop card
  card(s, 0.4, 0.9, 3.8, 3.6, C.panelbg, C.muted);
  s.addShape(pres.shapes.RECTANGLE, { x: 0.4, y: 0.9, w: 3.8, h: 0.42, fill: { color: C.muted }, line: { color: C.muted } });
  s.addText("INNER LOOP  (Where AI Started)", { x: 0.4, y: 0.9, w: 3.8, h: 0.42, align: "center", valign: "middle", fontSize: 12, bold: true, fontFace: F.head, color: C.white, margin: 0 });

  const innerItems = ["Code writing", "Code completion", "Test generation"];
  innerItems.forEach((item, i) => {
    s.addText(item, { x: 0.7, y: 1.5 + i * 0.42, w: 3.2, h: 0.38, fontSize: 13, fontFace: F.body, color: C.darkgray, bullet: false });
    s.addShape(pres.shapes.OVAL, { x: 0.72, y: 1.55 + i * 0.42, w: 0.14, h: 0.14, fill: { color: C.muted }, line: { color: C.muted } });
    s.addText(item, { x: 0.95, y: 1.47 + i * 0.42, w: 2.9, h: 0.35, fontSize: 13, fontFace: F.body, color: C.darkgray });
  });

  s.addShape(pres.shapes.RECTANGLE, { x: 0.7, y: 3.2, w: 3.2, h: 0.8, fill: { color: "D0D0D0" }, line: { color: "BBBBBB" } });
